import{_ as e,o as a,c as n,ag as o}from"./chunks/framework.C9sp7nFj.js";const u=JSON.parse('{"title":"Bot Channels","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/channels.md","filePath":"getting-started/channels.md","lastUpdated":1776579425000}'),i={name:"getting-started/channels.md"};function r(l,t,s,d,h,c){return a(),n("div",null,[...t[0]||(t[0]=[o('<h1 id="bot-channels" tabindex="-1">Bot Channels <a class="header-anchor" href="#bot-channels" aria-label="Permalink to &quot;Bot Channels&quot;">​</a></h1><p>Channels connect your Bot to various messaging platforms, allowing you to interact with it using your favorite chat applications.</p><h2 id="concept-unified-communication" tabindex="-1">Concept: Unified Communication <a class="header-anchor" href="#concept-unified-communication" aria-label="Permalink to &quot;Concept: Unified Communication&quot;">​</a></h2><p>Memoh acts as a hub that bridges different messaging services. You can configure multiple channels for a single bot, enabling it to chat on Telegram, Discord, Matrix, and more simultaneously.</p><hr><h2 id="supported-channels" tabindex="-1">Supported Channels <a class="header-anchor" href="#supported-channels" aria-label="Permalink to &quot;Supported Channels&quot;">​</a></h2><p>Configure your bot&#39;s connections from the <strong>Platforms</strong> tab in the Bot Detail page.</p><h3 id="platform-guides" tabindex="-1">Platform Guides <a class="header-anchor" href="#platform-guides" aria-label="Permalink to &quot;Platform Guides&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Platform</th><th>Guide</th><th>Notes</th></tr></thead><tbody><tr><td>Telegram</td><td><a href="/channels/telegram.html">Telegram Configuration</a></td><td>Strong attachment and streaming support</td></tr><tr><td>Feishu (Lark)</td><td><a href="/channels/feishu.html">Feishu Configuration</a></td><td>Supports webhook-style inbound mode</td></tr><tr><td>Discord</td><td><a href="/channels/discord.html">Discord Configuration</a></td><td>Good fit for communities and servers</td></tr><tr><td>QQ</td><td><a href="/channels/qq.html">QQ Configuration</a></td><td>Personal DM oriented</td></tr><tr><td>Matrix</td><td><a href="/channels/matrix.html">Matrix Configuration</a></td><td>Decentralized homeserver support</td></tr><tr><td>Misskey</td><td><a href="/channels/misskey.html">Misskey Configuration</a></td><td>Replies and reactions, no streaming</td></tr><tr><td>DingTalk</td><td><a href="/channels/dingtalk.html">DingTalk Configuration</a></td><td>Enterprise private/group chat</td></tr><tr><td>WeCom (WeWork)</td><td><a href="/channels/wecom.html">WeCom Configuration</a></td><td>Enterprise workspace integration</td></tr><tr><td>WeChat</td><td><a href="/channels/weixin.html">WeChat Configuration</a></td><td>Personal QR login flow</td></tr><tr><td>WeChat Official Account</td><td><a href="/channels/wechatoa.html">WeChat Official Account Configuration</a></td><td>Official account webhook flow</td></tr><tr><td>Slack</td><td><a href="/channels/slack.html">Slack Configuration</a></td><td>Replies, no streaming</td></tr></tbody></table><p>Two WeChat adapters exist on purpose:</p><ul><li><strong>WeChat</strong> is the QR-login personal messaging integration.</li><li><strong>WeChat Official Account</strong> is the official account / webhook integration for private-message scenarios.</li></ul><hr><h2 id="configuration-flow" tabindex="-1">Configuration Flow <a class="header-anchor" href="#configuration-flow" aria-label="Permalink to &quot;Configuration Flow&quot;">​</a></h2><h3 id="_1-adding-a-channel" tabindex="-1">1. Adding a Channel <a class="header-anchor" href="#_1-adding-a-channel" aria-label="Permalink to &quot;1. Adding a Channel&quot;">​</a></h3><ol><li>Click <strong>Add Channel</strong>.</li><li>Select the platform from the list.</li><li>Fill in the required credentials and configuration. The fields are dynamic and change based on the selected channel.</li></ol><h3 id="_2-common-fields" tabindex="-1">2. Common Fields <a class="header-anchor" href="#_2-common-fields" aria-label="Permalink to &quot;2. Common Fields&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Credentials</strong></td><td>API tokens, secrets, or bot keys provided by the platform.</td></tr><tr><td><strong>Disabled</strong></td><td>Quickly enable or disable a channel without removing its configuration.</td></tr><tr><td><strong>Routing</strong></td><td>Configure how messages are mapped between the platform and Memoh.</td></tr></tbody></table><h3 id="_3-special-case-feishu-webhook" tabindex="-1">3. Special Case: Feishu Webhook <a class="header-anchor" href="#_3-special-case-feishu-webhook" aria-label="Permalink to &quot;3. Special Case: Feishu Webhook&quot;">​</a></h3><p>If using <strong>Feishu</strong> in <code>webhook</code> inbound mode:</p><ol><li>Memoh will generate a <strong>Webhook Callback URL</strong>.</li><li>Copy this URL and paste it into your Feishu App&#39;s event configuration.</li><li>This allows Feishu to send messages directly to Memoh.</li></ol><h3 id="_4-special-case-wechat-qr-login" tabindex="-1">4. Special Case: WeChat QR Login <a class="header-anchor" href="#_4-special-case-wechat-qr-login" aria-label="Permalink to &quot;4. Special Case: WeChat QR Login&quot;">​</a></h3><p>If using <strong>WeChat</strong>:</p><ol><li>After enabling the channel, a QR code flow is provided for connecting.</li><li>Scan the QR code with WeChat to link the bot.</li></ol><h3 id="_5-special-case-wechat-official-account-webhook" tabindex="-1">5. Special Case: WeChat Official Account Webhook <a class="header-anchor" href="#_5-special-case-wechat-official-account-webhook" aria-label="Permalink to &quot;5. Special Case: WeChat Official Account Webhook&quot;">​</a></h3><p>If using <strong>WeChat Official Account</strong>:</p><ol><li>Create and save the channel first.</li><li>Memoh generates a <strong>Webhook Callback URL</strong> for that channel.</li><li>Copy the callback URL into the WeChat Official Account platform configuration.</li><li>Keep the configured <code>Token</code>, <code>Encryption Mode</code>, and optional AES settings aligned between Memoh and WeChat.</li></ol><h3 id="_6-special-case-dingtalk-stream-connection" tabindex="-1">6. Special Case: DingTalk Stream Connection <a class="header-anchor" href="#_6-special-case-dingtalk-stream-connection" aria-label="Permalink to &quot;6. Special Case: DingTalk Stream Connection&quot;">​</a></h3><p>If using <strong>DingTalk</strong>:</p><ol><li>Configure <code>App Key</code> and <code>App Secret</code>.</li><li>Save and enable the channel.</li><li>Memoh maintains the stream connection for inbound events; you do not need to manage a separate webhook callback URL for the standard setup.</li></ol><hr><h2 id="operations" tabindex="-1">Operations <a class="header-anchor" href="#operations" aria-label="Permalink to &quot;Operations&quot;">​</a></h2><ul><li><strong>Save</strong>: Update the configuration.</li><li><strong>Save and Enable</strong>: Update and immediately activate the channel.</li><li><strong>Enable/Disable Toggle</strong>: Switch the channel&#39;s active status.</li><li><strong>Delete</strong>: Permanently remove a channel&#39;s configuration.</li></ul>',32)])])}const f=e(i,[["render",r]]);export{u as __pageData,f as default};
